using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Shared state ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var notebook = new Notebook();

// --- Define tools ---
var searchTool = AIFunctionFactory.Create(
    ([Description("The search query string")] string query) =>
        WebSearch.SearchAsync(query, httpClient),
    nameof(WebSearch.SearchAsync),
    "Search the web for information on a topic. Returns relevant snippets and related topics.");

var takeNoteTool = AIFunctionFactory.Create(
    ([Description("Short descriptive title")] string title,
     [Description("The note body with key facts")] string content) =>
    {
        notebook.Add(title, content);
        return $"Note saved: \"{title}\"";
    },
    "TakeNote",
    "Save a research note. Use this to record important findings as you discover them.");

var readNotesTool = AIFunctionFactory.Create(
    notebook.GetAll,
    "ReadNotes",
    "Retrieve all previously saved research notes.");

var tools = new List<AITool> { searchTool, takeNoteTool, readNotesTool };

// --- Build the chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic:

        1. Search the web using at least 3-5 different queries covering various aspects.
        2. After each search, take notes on the most important findings.
        3. Once you have gathered enough information, read your notes.
        4. Produce a comprehensive, well-organized summary with sections and key takeaways.

        Be systematic: vary your queries to explore different angles of the topic.
        Always save notes before writing the final summary.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking tools.");

// --- Get the topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(" ", args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim()
        ?? throw new InvalidOperationException("No topic provided.");
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run the agent (streaming) ---
var session = new AgentSession();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0.3f,
    MaxOutputTokens = 4096,
    Tools = tools,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Please research the following topic and provide a comprehensive summary:\n\n{topic}",
    session,
    runOptions))
{
    // Show tool invocations as progress indicators
    if (update.Contents is { Count: > 0 })
    {
        foreach (var content in update.Contents)
        {
            if (content is FunctionCallContent fc)
            {
                var display = fc.Name switch
                {
                    nameof(WebSearch.SearchAsync) => $"  🌐 Searching: \"{fc.Arguments?["query"]}\"",
                    "TakeNote" => $"  📝 Note: \"{fc.Arguments?["title"]}\"",
                    "ReadNotes" => "  📖 Reading notes...",
                    _ => null
                };
                if (display is not null) Console.WriteLine(display);
            }
        }
    }

    // Stream assistant text to the console
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"✅ Research complete — {notebook.Count} note(s) collected.");

// ---------------------------------------------------------------------------
// Web search tool — uses DuckDuckGo Instant Answer API (no key required)
// ---------------------------------------------------------------------------
static class WebSearch
{
    public static async Task<string> SearchAsync(string query, HttpClient httpClient)
    {
        try
        {
            var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                    + "&format=json&no_html=1&skip_disambig=1";

            var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            var heading = json.GetProperty("Heading").GetString();
            var summary = json.GetProperty("Abstract").GetString();
            if (!string.IsNullOrEmpty(summary))
                results.Add($"## {heading}\n{summary}");

            var answer = json.GetProperty("Answer").GetString();
            if (!string.IsNullOrEmpty(answer))
                results.Add($"Quick answer: {answer}");

            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text)
                        && !string.IsNullOrEmpty(text.GetString()))
                    {
                        var link = topic.TryGetProperty("FirstURL", out var fu)
                            ? fu.GetString() : null;
                        results.Add($"- {text.GetString()}"
                            + (link is not null ? $"  ({link})" : ""));
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try different keywords.";
        }
        catch (Exception ex)
        {
            return $"Search error: {ex.Message}. Try a different query.";
        }
    }
}

// ---------------------------------------------------------------------------
// Notebook — in-memory note storage
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content) => _notes.Add((title, content));

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"### Note {i + 1}: {n.Title}\n{n.Content}"));
    }
}

